```sql
SELECT count(*) AS total_events FROM analytics.events;
```

```sql
SELECT COUNT(DISTINCT user_id) FROM analytics.events;
```

```sql
SELECT avg(duration_ms) AS avg_duration_ms FROM analytics.events;
```

```sql
SELECT event_type, COUNT(*) AS count FROM analytics.events GROUP BY event_type ORDER BY count DESC;
```

```sql
SELECT round(100.0 * count(*) FILTER (WHERE is_bounce) / count(*), 2) AS bounce_percentage FROM analytics.events;
```

```sql
SELECT SUM(lifetime_value) AS total_lifetime_value FROM analytics.users;
```

```sql
SELECT plan, COUNT(*) AS user_count FROM analytics.users GROUP BY plan ORDER BY user_count DESC;
```

```sql
SELECT MIN(price) AS min_price, MAX(price) AS max_price, AVG(price) AS avg_price FROM analytics.products;
```

```sql
SELECT device_type, COUNT(*) AS session_count FROM analytics.sessions GROUP BY device_type ORDER BY session_count DESC;
```

```sql
SELECT is_converted, AVG(duration_seconds) AS avg_duration_seconds FROM analytics.sessions GROUP BY is_converted;
```

```sql
SELECT plan, SUM(lifetime_value) AS total_lifetime_value FROM analytics.users GROUP BY plan ORDER BY total_lifetime_value DESC;
```

```sql
SELECT quantile(duration_ms, 0.95) AS p95_duration_ms FROM analytics.events;
```

```sql
SELECT utm_source, COUNT(*) AS total_sessions, SUM(CASE WHEN is_converted THEN 1 ELSE 0 END) AS converted_sessions, ROUND(100.0 * SUM(CASE WHEN is_converted THEN 1 ELSE 0 END) / COUNT(*), 2) AS conversion_rate FROM analytics.sessions WHERE utm_source IS NOT NULL GROUP BY utm_source ORDER BY conversion_rate DESC;
```

```sql
SELECT plan, country, SUM(lifetime_value) AS total_ltv, AVG(lifetime_value) AS avg_ltv, COUNT(*) AS user_count FROM analytics.users GROUP BY plan, country HAVING SUM(lifetime_value) > 10000 AND COUNT(*) >= 5;
```

```sql
SELECT * FROM analytics.users WHERE list_contains(tags, 'power_user');
```

```sql
SELECT device_type, os, COUNT(*) AS total_sessions, SUM(CASE WHEN is_converted THEN 1 ELSE 0 END) AS converted_sessions, ROUND(100.0 * SUM(CASE WHEN is_converted THEN 1 ELSE 0 END) / COUNT(*), 2) AS conversion_rate FROM analytics.sessions GROUP BY device_type, os ORDER BY conversion_rate DESC;
```

