SELECT * FROM analytics.products WHERE name LIKE 'Premium%' AND price BETWEEN 50 AND 200;
```

```sql
SELECT * FROM analytics.events WHERE referrer IS NOT NULL AND referrer != '' AND device_type = 'desktop' AND os = 'Windows';
